class DataStream:
    def __init__(self, value, k):
        self.value = value
        self.k = k
        self.history = []

    def consec(self, num):
        self.history.append(num)
        if len(self.history) < self.k:
            return False
        return all(x == self.value for x in self.history[-self.k:])

